  "code": "const pollMs = 100;
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'witch', 'enderman', 'pillager', 'ravager', 'hoglin', 'zoglin', 'piglin_brute', 'piglin', 'wither_skeleton']);
const arrowNames = new Set(['arrow', 'spectral_arrow', 'tipped_arrow']);

if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}

const findNearestThreat = function () {
  return bot.nearestEntity(function (entity) {
    if (!entity || !entity.isValid) return false;
    const isHostile = entity.kind === 'Hostile mobs' || entity.type === 'hostile' || hostileNames.has(entity.name || '');
    if (!isHostile) return false;
    return entity.position.distanceTo(bot.entity.position) < 40;
  });
};

const initialThreat = findNearestThreat();
if (!initialThreat) {
  return '<STOPPED>: No nearby hostiles to kite.';
}

startBackgroundSkill(bot, 'kite_nearest_hostile', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  movements.allowSprinting = true;
  bot.pathfinder.setMovements(movements);

  const startTime = Date.now();

  try {
    if (args.equipBow) {
      const bow = bot.inventory.items().find(function (item) { return item.name === 'bow'; });
      const hasArrows = bot.inventory.items().some(function (item) { return arrowNames.has(item.name); });
      if (bow && hasArrows) {
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        await bot.equip(bow, 'hand');
      }
    }

    while (canContinueBotAction(bot, token)) {
      const now = Date.now();
      if (now - startTime > args.maxDurationMs) break;

      const threat = findNearestThreat();
      if (!threat) {
        bot.pathfinder.setGoal(null);
        if (!await waitForActiveMs(bot, token, 1000, pollMs)) return;
        continue;
      }

      const dist = bot.entity.position.distanceTo(threat.position);

      if (dist < args.retreatThreshold) {
        const flatBotPos = bot.entity.position.offset(0, 0, 0);
        const flatThreatPos = threat.position.offset(0, 0, 0);
        const awayDir = flatBotPos.minus(flatThreatPos).normalize();

        const retreatDest = flatBotPos.plus(awayDir.scaled(args.preferredDistance - dist));

        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        bot.pathfinder.setGoal(new goals.GoalNear(retreatDest.x, retreatDest.y, retreatDest.z, 2));
      } else if (dist > args.preferredDistance + 4) {
        bot.pathfinder.setGoal(null);
      }

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.lookAt(threat.position.offset(0, threat.height || 1, 0), true);

      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) return;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
  }
});

return '<STARTED>: Kiting nearest hostile, maintaining distance of ' + args.preferredDistance + ' blocks.';"
}

